const assert = require('assert');
const LifecycleManager = require('../../../src/core/LifecycleManager');
const DiContainer = require('../../../src/core/DiContainer');

describe('LifecycleManager (Unit)', () => {
  beforeEach(() => {
    DiContainer.reset();
  });

  it('should inject properties and methods into a new instance', () => {
    class Repo {}
    class Service {
      repo;
      setConfig(cfg) {
        this.cfg = cfg;
      }
    }

    // Simulate DI injection values
    DiContainer.set('__inject:repo', new Repo());
    DiContainer.set('__injectMethod:setConfig', { env: 'test' });

    const instance = LifecycleManager.create(Service, 'Service');

    assert.ok(instance.repo instanceof Repo, 'Property injection failed');
    assert.deepStrictEqual(instance.cfg, { env: 'test' }, 'Setter injection failed');
  });

  it('should return the same instance on subsequent create calls (singleton)', () => {
    class Dummy {}

    const first = LifecycleManager.create(Dummy, 'Dummy');
    const second = LifecycleManager.create(Dummy, 'Dummy');

    assert.strictEqual(first, second, 'Instances are not the same (singleton violation)');
  });

  it('should register the instance in DiContainer', () => {
    class MyService {}

    const instance = LifecycleManager.create(MyService, 'MyService');
    const resolved = DiContainer.resolve('MyService');

    assert.strictEqual(instance, resolved, 'Instance not registered in DiContainer');
  });

  it('should initialize all services from registry', () => {
    class A {}
    class B {}

    const registry = new Map([
      ['A', A],
      ['B', B]
    ]);

    LifecycleManager.initializeAll(registry);

    assert.ok(DiContainer.has('A'), 'Service A not initialized');
    assert.ok(DiContainer.has('B'), 'Service B not initialized');
    assert.ok(DiContainer.resolve('A') instanceof A);
    assert.ok(DiContainer.resolve('B') instanceof B);
  });
});